#include <bits/stdc++.h>
using namespace std;
int t,q,l,r,s[10000007];
string str;
int main(){
    cin>>t;
    while(t--){
        cin>>str;
        for(int i=0;i<str.size();i++){
            if(str[i]=='P')
                s[i+1]=3;
            else if(str[i]=='p')
                s[i+1]=2;
            else if(str[i]=='G')
                s[i+1]=1;
            else
                s[i+1]=0;
            s[i+1]+=s[i];
        }
        cin>>q;
        while(q--){
            cin>>l>>r;
            cout<<s[r]-s[l-1]<<endl;
        }
    }
    return 0;
}
